pub struct BfsConfig {
    pub max_hops: u32,
    pub hub_guard: usize,
}

#[derive(Debug, Serialize, Clone)]
pub struct CalleeHit {
    pub name: String,
    pub path: String,
    pub line: u32,
    pub depth: u32,
    pub from: String,
}

